// Local storage fallback for when IPFS is not available

// Convert file to base64
export function fileToBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = () => resolve(reader.result);
    reader.onerror = error => reject(error);
  });
}

// Store file in local storage (for demo purposes only)
export async function storeFileLocally(file, tokenId) {
  try {
    const base64Data = await fileToBase64(file);

    // Store in localStorage with size limit check
    const storageKey = `nft_file_${tokenId}`;
    const fileInfo = {
      name: file.name,
      type: file.type,
      size: file.size,
      data: base64Data,
      timestamp: Date.now()
    };

    // Check localStorage size limit (roughly 5MB for most browsers)
    const dataSize = JSON.stringify(fileInfo).length;
    if (dataSize > 5 * 1024 * 1024) {
      // 5MB limit
      throw new Error('File too large for local storage');
    }
    localStorage.setItem(storageKey, JSON.stringify(fileInfo));
    return {
      success: true,
      localUrl: `local://${storageKey}`,
      size: dataSize
    };
  } catch (error) {
    console.error('Error storing file locally:', error);
    return {
      success: false,
      error: error.message
    };
  }
}

// Get file from local storage
export function getFileFromStorage(tokenId) {
  try {
    const storageKey = `nft_file_${tokenId}`;
    const storedData = localStorage.getItem(storageKey);
    if (!storedData) {
      return null;
    }
    return JSON.parse(storedData);
  } catch (error) {
    console.error('Error retrieving file from storage:', error);
    return null;
  }
}

