  const metadata = {
    name: name,
    description: description,
    attributes: [{
      trait_type: "Media Type",
      value: mediaType
    }, {
      trait_type: "Creator",
      value: creator
    }, {
      trait_type: "Storage",
      value: "Local"
    }, {
      trait_type: "Token ID",
      value: tokenId.toString()
    }],
    created_at: new Date().toISOString(),
    local_storage: true,
    local_file_key: `nft_file_${tokenId}` // Reference instead of full data
  };

  // Add preview URL (small thumbnail) instead of full file
  const localFile = getFileFromStorage(tokenId);
  if (localFile && localFile.data) {
    // For images, create a small thumbnail
    if (mediaType === 'image' && localFile.data.startsWith('data:image')) {
      // Use the original image but it will be loaded from localStorage when needed
      metadata.image = localFile.data;
      metadata.local_url = `local://nft_file_${tokenId}`;
    } else {
      // For audio/video, just store the reference
      metadata.local_url = `local://nft_file_${tokenId}`;
      metadata.media_preview = "Media stored locally";
    }
  }
  return metadata;
}

// Clean up old local storage files
export function cleanupOldFiles(maxAge = 7 * 24 * 60 * 60 * 1000) {
  // 7 days
  try {
    const now = Date.now();
    const keysToRemove = [];
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith('nft_file_')) {
        const data = localStorage.getItem(key);
        if (data) {
          const fileInfo = JSON.parse(data);
          if (now - fileInfo.timestamp > maxAge) {
            keysToRemove.push(key);
          }
        }
      }
    }
    keysToRemove.forEach(key => localStorage.removeItem(key));
    console.log(`Cleaned up ${keysToRemove.length} old local files`);
  } catch (error) {
    console.error('Error cleaning up local storage:', error);
  }
}

// Get local storage usage info
export function getLocalStorageInfo() {
  try {
    let totalSize = 0;
    let fileCount = 0;
    for (let i = 0; i < localStorage.length; i++) {
      const key = localStorage.key(i);
      if (key && key.startsWith('nft_file_')) {
        const data = localStorage.getItem(key);
        if (data) {
          totalSize += data.length;
          fileCount++;
        }
      }
    }
    return {
      fileCount,
      totalSize,
      totalSizeMB: (totalSize / (1024 * 1024)).toFixed(2),
      maxCapacity: '5MB (approximate browser limit)',
      usagePercentage: (totalSize / (5 * 1024 * 1024) * 100).toFixed(1)
    };
  } catch (error) {
    console.error('Error getting local storage info:', error);
    return {
      fileCount: 0,
      totalSize: 0,
      totalSizeMB: '0',
      maxCapacity: '5MB (approximate browser limit)',
      usagePercentage: '0'
    };
  }
